# [cfg (test)] mod tests { use super :: { Explainable , Fallibility , GuaranteeTag , MATRIX } ; # [doc = " Every op named in the spec §3 surface appears in the matrix exactly once."] # [doc = " Guard: removing or renaming any op from MATRIX makes this fail."] # [test] fn matrix_contains_all_eight_exported_ops () { let expected = ["serialize" , "deserialize" , "to_json" , "from_json" , "read_all" , "read" , "write" , "read_value" ,] ; for name in & expected { assert ! (MATRIX . iter () . any (| r | r . op == * name) , "matrix is missing op {:?} (spec §3)" , name) ; } assert_eq ! (MATRIX . len () , expected . len () , "matrix has unexpected extra or missing rows") ; } # [doc = " The `Exact` ops are exactly the five stated in spec §4 (serialize, to_json,"] # [doc = " read_all, read, write).  The `Empirical` ops are the three round-trip ops."] # [doc = " Guard: upgrading any `Empirical` to `Proven` makes this fail (VR-5)."] # [test] fn guarantee_tags_match_spec () { let exact_ops = ["serialize" , "to_json" , "read_all" , "read" , "write"] ; let empirical_ops = ["deserialize" , "from_json" , "read_value"] ; for op in & exact_ops { let row = MATRIX . iter () . find (| r | r . op == * op) . unwrap_or_else (| | panic ! ("op {:?} missing from matrix" , op)) ; assert_eq ! (row . guarantee , GuaranteeTag :: Exact , "op {:?} must be Exact (spec §4)" , op) ; } for op in & empirical_ops { let row = MATRIX . iter () . find (| r | r . op == * op) . unwrap_or_else (| | panic ! ("op {:?} missing from matrix" , op)) ; assert_eq ! (row . guarantee , GuaranteeTag :: Empirical , "op {:?} must be Empirical (spec §4 / VR-5 — round-trip property \
                 established by proptest, not by a checked theorem)" , op) ; } } # [doc = " No op is `Proven` (VR-5 — no round-trip theorem has been checked)."] # [doc = " Guard: upgrading any row to `Proven` without a checked theorem makes this fail."] # [test] fn no_op_is_proven_without_a_checked_theorem () { for row in MATRIX { assert_ne ! (row . guarantee , GuaranteeTag :: Proven , "op {:?} claims Proven without a checked theorem — \
                 downgrade to Empirical (VR-5 / spec §4.2 / §7-Q2)" , row . op) ; } } # [doc = " No op is `Declared` (VR-5 — an asserted-but-unchecked claim must be FLAGGED"] # [doc = " and is not the right tag for any op in this module)."] # [test] fn no_op_is_declared () { for row in MATRIX { assert_ne ! (row . guarantee , GuaranteeTag :: Declared , "op {:?} uses the Declared tag (VR-5 FLAG — must be FLAGGED explicitly)" , row . op) ; } } # [doc = " Fallible ops have a non-empty error set; total ops have an empty one (C1)."] # [doc = " Guard: setting a fallible op's error_set to \"\" makes this fail."] # [test] fn fallibility_and_error_set_are_consistent () { for row in MATRIX { match row . fallibility { Fallibility :: Total => assert ! (row . error_set . is_empty () , "total op {:?} must have an empty error_set (C1)" , row . op) , Fallibility :: Fallible => assert ! (! row . error_set . is_empty () , "fallible op {:?} must name its error set (C1)" , row . op) , } } } # [doc = " The `serialize` and `to_json` ops are fallible: they refuse a `Value` carrying a non-finite"] # [doc = " `f64` (JSON has no such literal; `serde_json` would silently emit `null` — a lossy,"] # [doc = " identity-colliding encoding). Refusing is never-silent (C1/G2)."] # [doc = " Guard: flipping either back to `Total` (re-introducing the silent-null path) makes this fail."] # [test] fn serialize_and_to_json_refuse_non_finite_fallibly () { for op in & ["serialize" , "to_json"] { let row = MATRIX . iter () . find (| r | r . op == * op) . unwrap_or_else (| | panic ! ("op {:?} missing" , op)) ; assert_eq ! (row . fallibility , Fallibility :: Fallible , "op {:?} must be fallible — non-finite f64 has no faithful JSON form (C1/G2)" , op) ; } } # [doc = " The io ops declare the `io` effect (C6)."] # [doc = " Guard: changing any io op's effect to \"none\" makes this fail."] # [test] fn io_ops_declare_io_effect () { let io_ops = ["read_all" , "read" , "write" , "read_value"] ; for op in & io_ops { let row = MATRIX . iter () . find (| r | r . op == * op) . unwrap_or_else (| | panic ! ("op {:?} missing" , op)) ; assert ! (row . effects . contains ("io") , "op {:?} must declare the io effect (C6 / spec §4)" , op) ; } } # [doc = " The serialize ops are pure (no effects)."] # [doc = " Guard: adding an effect to serialize/deserialize/to_json/from_json makes this fail."] # [test] fn serialize_ops_are_pure () { let pure_ops = ["serialize" , "deserialize" , "to_json" , "from_json"] ; for op in & pure_ops { let row = MATRIX . iter () . find (| r | r . op == * op) . unwrap_or_else (| | panic ! ("op {:?} missing" , op)) ; assert_eq ! (row . effects , "none" , "op {:?} must be pure/effect-free (C6 / spec §4)" , op) ; } } # [doc = " `read` declares the additional `alloc(Budget)` effect (C6/ADR-015)."] # [test] fn read_declares_alloc_budget () { let row = MATRIX . iter () . find (| r | r . op == "read") . expect ("read row") ; assert ! (row . effects . contains ("alloc") , "read must declare alloc(Budget) effect (C6/ADR-015)") ; } # [doc = " The three fallible decode ops carry EXPLAIN artifacts (C3 — RFC-0013 locus)."] # [doc = " Guard: removing EXPLAIN from any decode op makes this fail."] # [test] fn decode_ops_are_explainable () { let explain_ops = ["deserialize" , "from_json" , "read_value"] ; for op in & explain_ops { let row = MATRIX . iter () . find (| r | r . op == * op) . unwrap_or_else (| | panic ! ("op {:?} missing" , op)) ; assert_eq ! (row . explainable , Explainable :: Yes , "op {:?} must be EXPLAIN-able (C3 — RFC-0013 diagnostic @locus)" , op) ; } } # [doc = " The serialize/io write ops are `NotApplicable` for EXPLAIN (no"] # [doc = " selection/conversion/approximation)."] # [test] fn projection_ops_are_not_explainable () { let na_ops = ["serialize" , "to_json"] ; for op in & na_ops { let row = MATRIX . iter () . find (| r | r . op == * op) . unwrap_or_else (| | panic ! ("op {:?} missing" , op)) ; assert_eq ! (row . explainable , Explainable :: NotApplicable , "op {:?} must be NotApplicable for EXPLAIN (C3 n/a — faithful projection)" , op) ; } } }

# [doc = " A `Value` carrying a non-finite `f64` (`NaN`/`±∞`) in a `Dense`/`Vsa` payload has no faithful"] # [doc = " JSON representation (`serde_json` would silently emit `null`), so it is refused here."] # [doc = ""] # [doc = " Returns `Err(SerError::OutOfDomain)` naming the payload index of the first non-finite scalar;"] # [doc = " `Ok(())` when every scalar is finite (or the payload has no `f64`)."] fn check_json_representable (v : & Value) -> Result < () , SerError > { let scalars : & [f64] = match v . payload () { Payload :: Scalars (s) | Payload :: Hypervector (s) => s , Payload :: Bits (_) | Payload :: Trits (_) => return Ok (()) , Payload :: Seq (elems) => { for e in elems { check_json_representable (e) ? ; } return Ok (()) ; } Payload :: Bytes (_) => return Ok (()) , Payload :: Float (_) => return Ok (()) , } ; if let Some (pos) = scalars . iter () . position (| x | ! x . is_finite ()) { return Err (SerError :: OutOfDomain { path : FieldPath :: from_static ("payload") , why : format ! ("non-finite f64 at payload index {pos} has no JSON representation \
                 (serde_json would silently emit null, losing NaN/±∞ and colliding identity); \
                 refused — never-silent (C1/G2)") , }) ; } Ok (()) }
